zztop() { kill="$(ps -aO %mem,%cpu --sort -%mem|bat --line-range 2:12|column --table --table-columns-limit 8 --table-columns p,m,c,s,tty,time,cmd,cmd2 --table-hide tty,time,cmd|sed -e "s/${PREFIX//\//\\/}*\//____\//g"|bat -ppfljs --line-range 2:12|fzf --with-nth 2.. --preview 'ps wup {1}|bat -ppfljs' --preview-window 'wrap,top,4,border-bottom' --bind 'load:reload-sync(sleep 2; ps -aO %mem,%cpu --sort -%mem|bat --line-range 2:12|column --table --table-columns-limit 8 --table-columns p,m,c,s,tty,time,cmd,cmd2 --table-hide tty,time,cmd|sed -e "s/${PREFIX//\//\\/}*\//\//g"|bat -ppfljs --line-range 2:12)' --header "$(printf %b "\e[7;96m %\e[45mM\e[40m \e[94m CPU \e[95m S \e[92m Command \e[0m >> ";)" --tmux '100%,22' --accept-nth 1)"; printf %b "\e[0m\n\e[7m $(ps p $kill 2>/dev/null|tr -s " " " "|cut -f5- -d" ") \e[0m\n\n"; }; 
